import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';

// ============================================================================
// LOCK-IN COEFFICIENT MATH (ported from Elite Power Dynamics model)
// ============================================================================

/*
 * The Lock-In Formula (sigmoid):
 * L(t) = L0 + (Lmax - L0) / (1 + exp(-k * (activity - t0)))
 *
 * Where:
 * - L0 = baseline lock-in for new threads
 * - Lmax = maximum lock-in (fully permanent memory)
 * - k = lock speed (modulated by interventions)
 * - t0 = activity threshold (inflection point)
 * - activity = composite of retrievals, reinforcements, network density
 */

const LOCK_IN_CONFIG = {
  L0: 0.15,           // New thread baseline
  Lmax: 0.95,         // Fully locked memory
  L_CRITICAL: 0.70,   // Above this = locked (permanent)
  L_DRIFT: 0.30,      // Below this = drifting (at risk)
  t0: 5,              // Activity threshold for inflection
  baseK: 0.4,         // Base lock speed
};

// Calculate activity score from thread properties
const calculateActivity = (thread, config) => {
  const {
    retrievalWeight,
    reinforcementWeight,
    networkWeight,
    anchorWeight,
  } = config;

  // Retrieval heat: how often has this thread been accessed?
  const retrievalScore = Math.min(10, thread.retrievals) / 10;

  // Reinforcement: has this connection been re-confirmed in later sessions?
  const reinforcementScore = Math.min(5, thread.reinforcements) / 5;

  // Network density: how many other locked threads touch this one?
  const networkScore = Math.min(8, thread.connectedLockedThreads) / 8;

  // Context anchoring: is this tied to an active project/topic?
  const anchorScore = thread.activeContexts > 0 ? Math.min(1, thread.activeContexts / 3) : 0;

  // Weighted combination (these are the "interventions")
  const activity = (
    retrievalScore * retrievalWeight +
    reinforcementScore * reinforcementWeight +
    networkScore * networkWeight +
    anchorScore * anchorWeight
  ) * 10; // Scale to 0-10 range

  return activity;
};

// The sigmoid lock-in function
const calculateLockIn = (activity, k = LOCK_IN_CONFIG.baseK) => {
  const { L0, Lmax, t0 } = LOCK_IN_CONFIG;
  return L0 + (Lmax - L0) / (1 + Math.exp(-k * (activity - t0)));
};

// Generate lock-in trajectory (for visualization)
const generateLockInTrajectory = (currentActivity, k, steps = 20) => {
  const trajectory = [];
  for (let i = 0; i <= steps; i++) {
    const activity = (i / steps) * 10; // 0 to 10
    const lockIn = calculateLockIn(activity, k);
    trajectory.push({ activity, lockIn, isCurrent: Math.abs(activity - currentActivity) < 0.3 });
  }
  return trajectory;
};

// Classify thread state
const classifyThreadState = (lockIn) => {
  if (lockIn >= LOCK_IN_CONFIG.L_CRITICAL) return 'locked';
  if (lockIn <= LOCK_IN_CONFIG.L_DRIFT) return 'drifting';
  return 'active';
};

