// Simulate activity data for threads
const simulateThreadActivity = (thread, sessions) => {
  // Base activity on shared tags (more tags = more likely to be retrieved)
  const tagOverlap = thread.resonance.sharedTags?.length || 0;

  // Simulate retrieval count based on resonance and recency
  const sessionGap = thread.sessionGap;
  const baseRetrievals = Math.max(0, 5 - sessionGap) + tagOverlap * 2;
  const retrievals = Math.floor(baseRetrievals * (0.5 + Math.random() * 0.5));

  // Reinforcement = mentioned again in later sessions
  const reinforcements = sessionGap > 2 ? Math.floor(Math.random() * 3) : Math.floor(Math.random() * 2);

  // Connected locked threads (network effect)
  const connectedLockedThreads = Math.floor(Math.random() * 4);

  // Active contexts (is this part of current work?)
  const isRecentTopic = thread.resonance.sharedTags?.some(t => 
    ['memory', 'lock-in', 'edge', 'config', 'visualization'].includes(t)
  );
  const activeContexts = isRecentTopic ? Math.floor(1 + Math.random() * 2) : 0;

  return {
    retrievals,
    reinforcements,
    connectedLockedThreads,
    activeContexts,
  };
};

// ============================================================================
// RESONANCE CALCULATION
// ============================================================================

const calculateResonance = (node1, node2, config) => {
  const tags1 = new Set(node1.tags || []);
  const tags2 = new Set(node2.tags || []);
  const intersection = [...tags1].filter(t => tags2.has(t));
  const union = new Set([...tags1, ...tags2]);
  const tagScore = union.size > 0 ? intersection.length / union.size : 0;

  const sameType = node1.type === node2.type;
  const typeScore = sameType ? 1.0 : 0.5;

  const confDiff = Math.abs(node1.confidence - node2.confidence) / 100;
  const confScore = 1 - confDiff;

  const score = (tagScore * 0.6) + (typeScore * 0.2) + (confScore * 0.2);

  return {
    score,
    tagScore,
    sharedTags: intersection,
    wouldConnect: score >= config.crossSessionThreshold,
  };
};

// Find all cross-session connections with lock-in data
const findCrossSessionThreads = (sessions, config, activityConfig) => {
  const threads = [];

  for (let i = 0; i < sessions.length; i++) {
    for (let j = i + 1; j < sessions.length; j++) {
      const session1 = sessions[i];
      const session2 = sessions[j];

      session1.nodes.forEach(node1 => {
        session2.nodes.forEach(node2 => {
          const resonance = calculateResonance(node1, node2, config);
          if (resonance.wouldConnect) {
            const baseThread = {
              id: `${node1.id}-${node2.id}`,
              from: { sessionId: session1.id, nodeId: node1.id, node: node1 },
              to: { sessionId: session2.id, nodeId: node2.id, node: node2 },
              resonance,
              sessionGap: j - i,
              timeGap: session2.date - session1.date,
            };

            // Add activity metrics
            const activity = simulateThreadActivity(baseThread, sessions);
            const activityScore = calculateActivity({ ...baseThread, ...activity }, activityConfig);
            const lockIn = calculateLockIn(activityScore, activityConfig.lockSpeed);
            const state = classifyThreadState(lockIn);

            threads.push({
              ...baseThread,
              ...activity,
              activityScore,
              lockIn,
              state,
            });
          }
        });
      });
    }
  }

  return threads;
};

// ============================================================================
// WARNING SYSTEM
// ============================================================================

const analyzeWarnings = (sessions, threads, config) => {
  const warnings = [];

  // Count threads by state
  const locked = threads.filter(t => t.state === 'locked').length;
  const drifting = threads.filter(t => t.state === 'drifting').length;
  const active = threads.filter(t => t.state === 'active').length;

  // MEMORY OSSIFICATION - too many locked threads (can't learn new patterns)
  if (threads.length > 5 && locked / threads.length > 0.6) {
    warnings.push({
      level: 'warning',
      code: 'MEMORY_OSSIFICATION',
      title: 'Memory Ossification',
      message: `${Math.round(locked / threads.length * 100)}% of threads are locked`,
      suggestion: 'Memory may be too rigid. New patterns harder to form.',
    });
  }

  // CONTEXT DRIFT - too many drifting threads
  if (threads.length > 5 && drifting / threads.length > 0.4) {
    warnings.push({
      level: 'critical',
      code: 'CONTEXT_DRIFT',
      title: 'Context Drift',
      message: `${drifting} threads are drifting toward loss`,
      suggestion: 'Retrieve or reinforce these memories before they fade.',
    });
  }

  // TEMPORAL AMNESIA - no locked threads spanning > 7 days
  const oldLockedThreads = threads.filter(
    t => t.state === 'locked' && t.timeGap > 7 * 24 * 60 * 60 * 1000
  );
  if (sessions.length > 3 && oldLockedThreads.length === 0) {
    warnings.push({
      level: 'critical',
      code: 'TEMPORAL_AMNESIA',
      title: 'Temporal Amnesia',
      message: 'No permanent memories span more than a week',
      suggestion: 'Long-term memory formation is failing.',
    });
  }

  // THIN THREAD - very few cross-session connections overall
  const totalNodes = sessions.reduce((sum, s) => sum + s.nodes.length, 0);
  if (threads.length < totalNodes * 0.3 && sessions.length > 2) {
    warnings.push({
      level: 'warning',
      code: 'THIN_THREAD',
      title: 'Thin Thread',
      message: `Only ${threads.length} cross-session threads`,
      suggestion: 'Memory continuity is fragile. Lower threshold.',
    });
  }

  // INFLECTION ZONE - threads near the tipping point
  const nearInflection = threads.filter(t => t.lockIn > 0.35 && t.lockIn < 0.55);
  if (nearInflection.length > 3) {
    warnings.push({
      level: 'info',
      code: 'INFLECTION_ZONE',
      title: 'Inflection Zone',
      message: `${nearInflection.length} threads at critical tipping point`,
      suggestion: 'Small interventions have maximum impact here.',
    });
  }

  return warnings.sort((a, b) => {
    const priority = { critical: 0, warning: 1, info: 2 };
    return priority[a.level] - priority[b.level];
  });
};

