const LockInGauge = ({ lockIn, state, size = 60 }) => {
  const radius = (size - 8) / 2;
  const circumference = radius * Math.PI; // Half circle
  const progress = lockIn * circumference;

  const getColor = () => STATE_COLORS[state];

  return (
    <svg width={size} height={size / 2 + 10} className="block">
      {/* Background arc */}
      <path
        d={`M 4 ${size/2} A ${radius} ${radius} 0 0 1 ${size - 4} ${size/2}`}
        fill="none"
        stroke="rgba(255,255,255,0.1)"
        strokeWidth="6"
        strokeLinecap="round"
      />
      {/* Progress arc */}
      <path
        d={`M 4 ${size/2} A ${radius} ${radius} 0 0 1 ${size - 4} ${size/2}`}
        fill="none"
        stroke={getColor()}
        strokeWidth="6"
        strokeLinecap="round"
        strokeDasharray={`${progress} ${circumference}`}
        style={{ filter: `drop-shadow(0 0 4px ${getColor()})` }}
      />
      {/* Value text */}
      <text
        x={size / 2}
        y={size / 2 - 2}
        textAnchor="middle"
        fill={getColor()}
        fontSize="12"
        fontWeight="bold"
        fontFamily="monospace"
      >
        {(lockIn * 100).toFixed(0)}%
      </text>
      {/* State label */}
      <text
        x={size / 2}
        y={size / 2 + 12}
        textAnchor="middle"
        fill="rgba(255,255,255,0.5)"
        fontSize="8"
      >
        {state.toUpperCase()}
      </text>
    </svg>
  );
};

const SigmoidChart = ({ trajectory, currentActivity, lockIn, width = 200, height = 80 }) => {
  const padding = { top: 10, right: 10, bottom: 20, left: 30 };
  const chartWidth = width - padding.left - padding.right;
  const chartHeight = height - padding.top - padding.bottom;

  // Scale functions
  const xScale = (activity) => padding.left + (activity / 10) * chartWidth;
  const yScale = (l) => padding.top + chartHeight - (l * chartHeight);

  // Generate path
  const pathD = trajectory.map((point, i) => {
    const x = xScale(point.activity);
    const y = yScale(point.lockIn);
    return `${i === 0 ? 'M' : 'L'} ${x} ${y}`;
  }).join(' ');

  return (
    <svg width={width} height={height} className="block">
      {/* Grid */}
      <line x1={padding.left} y1={yScale(LOCK_IN_CONFIG.L_CRITICAL)} x2={width - padding.right} y2={yScale(LOCK_IN_CONFIG.L_CRITICAL)} stroke="#22c55e" strokeWidth="1" strokeDasharray="4,4" opacity="0.5" />
      <line x1={padding.left} y1={yScale(LOCK_IN_CONFIG.L_DRIFT)} x2={width - padding.right} y2={yScale(LOCK_IN_CONFIG.L_DRIFT)} stroke="#f97316" strokeWidth="1" strokeDasharray="4,4" opacity="0.5" />

      {/* Axes */}
      <line x1={padding.left} y1={padding.top} x2={padding.left} y2={height - padding.bottom} stroke="rgba(255,255,255,0.3)" strokeWidth="1" />
      <line x1={padding.left} y1={height - padding.bottom} x2={width - padding.right} y2={height - padding.bottom} stroke="rgba(255,255,255,0.3)" strokeWidth="1" />

      {/* Labels */}
      <text x={padding.left - 5} y={yScale(1)} textAnchor="end" fill="rgba(255,255,255,0.4)" fontSize="8">1.0</text>
      <text x={padding.left - 5} y={yScale(0.5)} textAnchor="end" fill="rgba(255,255,255,0.4)" fontSize="8">0.5</text>
      <text x={padding.left - 5} y={yScale(0)} textAnchor="end" fill="rgba(255,255,255,0.4)" fontSize="8">0</text>
      <text x={width / 2} y={height - 2} textAnchor="middle" fill="rgba(255,255,255,0.4)" fontSize="8">Activity →</text>

      {/* Curve */}
      <path d={pathD} fill="none" stroke="#22d3ee" strokeWidth="2" />

      {/* Current position */}
      <circle cx={xScale(currentActivity)} cy={yScale(lockIn)} r="5" fill="#22d3ee" stroke="white" strokeWidth="2" />

      {/* Threshold labels */}
      <text x={width - padding.right - 2} y={yScale(LOCK_IN_CONFIG.L_CRITICAL) - 3} textAnchor="end" fill="#22c55e" fontSize="7">LOCKED</text>
      <text x={width - padding.right - 2} y={yScale(LOCK_IN_CONFIG.L_DRIFT) + 10} textAnchor="end" fill="#f97316" fontSize="7">DRIFT</text>
    </svg>
  );
};

const SessionStack = ({ 
  session, 
  selectedNode, 
  onNodeSelect, 
  highlightedNodes,
  onNodePosition,
}) => {
  const stackRef = useRef(null);
  const nodeRefs = useRef({});

  useEffect(() => {
    if (!stackRef.current) return;

    const positions = {};
    session.nodes.forEach(node => {
      const nodeEl = nodeRefs.current[node.id];
      if (nodeEl) {
        const nodeRect = nodeEl.getBoundingClientRect();
        positions[node.id] = {
          x: nodeRect.left + nodeRect.width / 2,
          y: nodeRect.top + nodeRect.height / 2,
        };
      }
    });

    onNodePosition(session.id, positions);
  }, [session, onNodePosition]);

  const formatDate = (date) => {
    const now = new Date();
    const diff = now - date;
    const days = Math.floor(diff / (24 * 60 * 60 * 1000));

    if (days === 0) return 'Today';
    if (days === 1) return 'Yesterday';
    if (days < 7) return `${days}d ago`;
    return `${Math.floor(days / 7)}w ago`;
  };

  return (
    <div ref={stackRef} className="flex-shrink-0 w-44">
      <div className="mb-2 text-center">
        <div className="text-xs text-cyan-400 font-medium">{formatDate(session.date)}</div>
        <div className="text-xs text-white/40 truncate">{session.title}</div>
      </div>

      <div className="space-y-1.5 bg-black/30 rounded-xl p-2 border border-white/10">
        {session.nodes.map((node) => {
          const isSelected = selectedNode?.id === node.id;
          const isHighlighted = highlightedNodes.has(node.id);

          return (
            <div
              key={node.id}
              ref={el => nodeRefs.current[node.id] = el}
              onClick={() => onNodeSelect(node, session)}
              className={`p-2 rounded-lg cursor-pointer transition-all duration-200 ${isSelected ? 'ring-2 ring-cyan-400' : ''} ${isHighlighted && !isSelected ? 'ring-1 ring-cyan-400/50' : ''}`}
              style={{
                backgroundColor: TYPE_COLORS[node.type] + (isHighlighted ? '40' : '20'),
                borderLeft: `3px solid ${TYPE_COLORS[node.type]}`,
              }}
            >
              <div className="flex items-center gap-1 mb-1">
                <span className="text-xs font-bold" style={{ color: TYPE_COLORS[node.type] }}>
                  {node.type.slice(0, 3)}
                </span>
                <span className="text-xs text-white/40">{node.confidence}%</span>
              </div>
              <p className="text-xs text-white/70 line-clamp-2">{node.content}</p>
            </div>
          );
        })}
      </div>
    </div>
  );
};

const ThreadCanvas = ({ threads, nodePositions, containerRef, selectedThread, highlightedThreads }) => {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    const container = containerRef.current;
    if (!canvas || !container) return;

    const containerRect = container.getBoundingClientRect();
    canvas.width = containerRect.width;
    canvas.height = containerRect.height;

    const ctx = canvas.getContext('2d');
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    threads.forEach(thread => {
      const fromPos = nodePositions[thread.from.nodeId];
      const toPos = nodePositions[thread.to.nodeId];

      if (!fromPos || !toPos) return;

      const x1 = fromPos.x - containerRect.left;
      const y1 = fromPos.y - containerRect.top;
      const x2 = toPos.x - containerRect.left;
      const y2 = toPos.y - containerRect.top;

      const isHighlighted = highlightedThreads.has(thread.id);
      const isSelected = selectedThread?.id === thread.id;

      // Color and thickness based on lock-in state
      const stateColor = STATE_COLORS[thread.state];
      const baseAlpha = 0.2 + thread.lockIn * 0.6;
      const alpha = isSelected ? 1 : isHighlighted ? 0.8 : baseAlpha;
      const lineWidth = isSelected ? 4 : isHighlighted ? 3 : 1 + thread.lockIn * 2;

      ctx.beginPath();
      ctx.strokeStyle = isSelected || isHighlighted ? stateColor : `rgba(34, 211, 238, ${alpha})`;
      ctx.lineWidth = lineWidth;

      if (thread.state === 'drifting') {
        ctx.setLineDash([4, 4]);
      } else {
        ctx.setLineDash([]);
      }

      const midX = (x1 + x2) / 2;
      const midY = Math.min(y1, y2) - 20 - thread.sessionGap * 12;

      ctx.moveTo(x1, y1);
      ctx.quadraticCurveTo(midX, midY, x2, y2);
      ctx.stroke();

      // Lock-in indicator at midpoint
      if (isHighlighted || isSelected) {
        const t = 0.5;
        const mx = (1-t)*(1-t)*x1 + 2*(1-t)*t*midX + t*t*x2;
        const my = (1-t)*(1-t)*y1 + 2*(1-t)*t*midY + t*t*y2;

        // Circle with lock-in fill
        ctx.beginPath();
        ctx.arc(mx, my, 8, 0, Math.PI * 2);
        ctx.fillStyle = stateColor;
        ctx.fill();

        ctx.font = 'bold 8px monospace';
        ctx.fillStyle = 'white';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText(`${Math.round(thread.lockIn * 100)}`, mx, my);
      }

      ctx.setLineDash([]);
    });
  }, [threads, nodePositions, containerRef, selectedThread, highlightedThreads]);

  return (
    <canvas ref={canvasRef} className="absolute inset-0 pointer-events-none" style={{ zIndex: 10 }} />
  );
};

const ThreadDetail = ({ thread, activityConfig, onClose }) => {
  if (!thread) return null;

  const trajectory = generateLockInTrajectory(thread.activityScore, activityConfig.lockSpeed);

  return (
    <div className="bg-black/40 rounded-xl border border-white/10 p-3">
      <div className="flex items-center justify-between mb-3">
        <span className="text-sm font-medium" style={{ color: STATE_COLORS[thread.state] }}>
          {thread.state.toUpperCase()} Thread
        </span>
        <button onClick={onClose} className="text-white/40 hover:text-white/60">✕</button>
      </div>

      {/* Lock-In Gauge */}
      <div className="flex justify-center mb-3">
        <LockInGauge lockIn={thread.lockIn} state={thread.state} size={80} />
      </div>

      {/* Sigmoid Trajectory */}
      <div className="bg-black/30 rounded-lg p-2 mb-3">
        <div className="text-xs text-white/40 mb-1 text-center">Lock-In Trajectory</div>
        <SigmoidChart 
          trajectory={trajectory}
          currentActivity={thread.activityScore}
          lockIn={thread.lockIn}
          width={220}
          height={80}
        />
      </div>

      {/* Activity Breakdown */}
      <div className="space-y-2 mb-3">
        <div className="text-xs text-white/40">Activity Factors</div>
        {[
          { label: 'Retrievals', value: thread.retrievals, max: 10, color: '#22d3ee' },
          { label: 'Reinforcements', value: thread.reinforcements, max: 5, color: '#a78bfa' },
          { label: 'Network', value: thread.connectedLockedThreads, max: 8, color: '#34d399' },
          { label: 'Active Contexts', value: thread.activeContexts, max: 3, color: '#fbbf24' },
        ].map(({ label, value, max, color }) => (
          <div key={label}>
            <div className="flex justify-between text-xs mb-0.5">
              <span className="text-white/50">{label}</span>
              <span style={{ color }}>{value}/{max}</span>
            </div>
            <div className="h-1 bg-white/10 rounded-full overflow-hidden">
              <div className="h-full rounded-full" style={{ width: `${(value / max) * 100}%`, backgroundColor: color }} />
            </div>
          </div>
        ))}
      </div>

      {/* Nodes */}
      <div className="space-y-2">
        {[thread.from, thread.to].map((end, idx) => (
          <div key={end.nodeId} className="p-2 rounded-lg" style={{ backgroundColor: TYPE_COLORS[end.node.type] + '20' }}>
            <div className="text-xs text-white/40 mb-1">{idx === 0 ? 'From' : 'To'}</div>
            <p className="text-xs text-white/70 line-clamp-2">{end.node.content}</p>
          </div>
        ))}
      </div>

      {/* Shared tags */}
      {thread.resonance.sharedTags?.length > 0 && (
        <div className="mt-3 pt-3 border-t border-white/10">
          <div className="text-xs text-white/40 mb-1">Shared Tags</div>
          <div className="flex flex-wrap gap-1">
            {thread.resonance.sharedTags.map(tag => (
              <span key={tag} className="text-xs bg-cyan-500/20 text-cyan-300 px-1.5 py-0.5 rounded">{tag}</span>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

const WarningPanel = ({ warnings }) => {
  if (warnings.length === 0) {
    return (
      <div className="bg-green-500/10 border border-green-500/30 rounded-xl p-3 text-center">
        <div className="text-green-400 text-xl mb-1">✓</div>
        <div className="text-green-400 text-sm font-medium">Healthy Memory</div>
      </div>
    );
  }

  const colors = { critical: 'red', warning: 'yellow', info: 'cyan' };
  const icons = { critical: '🔴', warning: '🟡', info: '🔵' };

  return (
    <div className="space-y-2 max-h-48 overflow-y-auto">
      {warnings.map((warning, idx) => (
        <div
          key={idx}
          className={`rounded-lg p-2 border bg-${colors[warning.level]}-500/10 border-${colors[warning.level]}-500/40`}
          style={{
            backgroundColor: warning.level === 'critical' ? 'rgba(239,68,68,0.1)' : warning.level === 'warning' ? 'rgba(234,179,8,0.1)' : 'rgba(34,211,238,0.1)',
            borderColor: warning.level === 'critical' ? 'rgba(239,68,68,0.4)' : warning.level === 'warning' ? 'rgba(234,179,8,0.4)' : 'rgba(34,211,238,0.4)',
          }}
        >
          <div className="flex items-start gap-2">
            <span>{icons[warning.level]}</span>
            <div>
              <div className="text-sm font-medium" style={{ color: warning.level === 'critical' ? '#f87171' : warning.level === 'warning' ? '#fbbf24' : '#22d3ee' }}>
                {warning.title}
              </div>
              <div className="text-xs text-white/60">{warning.message}</div>
              <div className="text-xs text-white/40 mt-0.5">💡 {warning.suggestion}</div>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
};

const Slider = ({ label, value, onChange, min, max, step = 0.01, color = '#22d3ee' }) => (
  <div className="mb-3">
    <div className="flex justify-between items-center mb-1">
      <span className="text-xs text-white/60">{label}</span>
      <span className="text-xs font-mono" style={{ color }}>{value.toFixed(2)}</span>
    </div>
    <input
      type="range" min={min} max={max} step={step} value={value}
      onChange={(e) => onChange(parseFloat(e.target.value))}
      className="w-full h-1.5 bg-white/10 rounded-lg appearance-none cursor-pointer"
      style={{ accentColor: color }}
    />
  </div>
);

// ============================================================================
// MAIN COMPONENT
// ============================================================================

export default function TemporalLockInMap() {
  const containerRef = useRef(null);

  const [sessions] = useState(SAMPLE_SESSIONS);
  const [config, setConfig] = useState({ crossSessionThreshold: 0.25 });

  const [activityConfig, setActivityConfig] = useState({
    retrievalWeight: 0.35,
    reinforcementWeight: 0.25,
    networkWeight: 0.20,
    anchorWeight: 0.20,
    lockSpeed: 0.4,
  });

  const [nodePositions, setNodePositions] = useState({});
  const [selectedNode, setSelectedNode] = useState(null);
  const [selectedThread, setSelectedThread] = useState(null);
  const [highlightedNodes, setHighlightedNodes] = useState(new Set());
  const [highlightedThreads, setHighlightedThreads] = useState(new Set());

  // Calculate threads with lock-in
  const threads = useMemo(() => {
    return findCrossSessionThreads(sessions, config, activityConfig);
  }, [sessions, config, activityConfig]);

  // Analyze warnings
  const warnings = useMemo(() => {
    return analyzeWarnings(sessions, threads, config);
  }, [sessions, threads, config]);

  // Stats
  const stats = useMemo(() => {
    const locked = threads.filter(t => t.state === 'locked').length;
    const active = threads.filter(t => t.state === 'active').length;
    const drifting = threads.filter(t => t.state === 'drifting').length;
    const avgLockIn = threads.length > 0 ? threads.reduce((s, t) => s + t.lockIn, 0) / threads.length : 0;

    return { total: threads.length, locked, active, drifting, avgLockIn };
  }, [threads]);

  const handleNodePosition = useCallback((sessionId, positions) => {
    setNodePositions(prev => ({ ...prev, ...positions }));
  }, []);

  const handleNodeSelect = useCallback((node, session) => {
    setSelectedNode({ ...node, session });
    setSelectedThread(null);

    const connectedThreads = threads.filter(
      t => t.from.nodeId === node.id || t.to.nodeId === node.id
    );

    const connectedNodeIds = new Set([node.id]);
    connectedThreads.forEach(t => {
      connectedNodeIds.add(t.from.nodeId);
      connectedNodeIds.add(t.to.nodeId);
    });

    setHighlightedNodes(connectedNodeIds);
    setHighlightedThreads(new Set(connectedThreads.map(t => t.id)));
  }, [threads]);

  const clearSelection = useCallback(() => {
    setSelectedNode(null);
    setSelectedThread(null);
    setHighlightedNodes(new Set());
    setHighlightedThreads(new Set());
  }, []);

  return (
    <div className="min-h-screen bg-gradient-to-b from-slate-950 via-slate-900 to-slate-950 text-white p-4">
      {/* Header */}
      <div className="text-center mb-4">
        <h1 className="text-2xl font-light tracking-wide">
          <span className="text-cyan-400">Lock-In</span> Coefficient Map
        </h1>
        <p className="text-white/40 text-sm">Memory threads with sigmoid lock-in dynamics</p>
      </div>

      {/* Stats */}
      <div className="flex justify-center gap-6 mb-4">
        {[
          { label: 'Threads', value: stats.total, color: 'white' },
          { label: 'Locked', value: stats.locked, color: '#22c55e' },
          { label: 'Active', value: stats.active, color: '#22d3ee' },
          { label: 'Drifting', value: stats.drifting, color: '#f97316' },
          { label: 'Avg L(t)', value: `${(stats.avgLockIn * 100).toFixed(0)}%`, color: stats.avgLockIn > 0.5 ? '#22c55e' : stats.avgLockIn > 0.3 ? '#22d3ee' : '#f97316' },
        ].map(({ label, value, color }) => (
          <div key={label} className="text-center">
            <div className="text-xl font-mono" style={{ color }}>{value}</div>
            <div className="text-xs text-white/40">{label}</div>
          </div>
        ))}
      </div>

      <div className="flex gap-4">
        {/* Left Panel */}
        <div className="w-60 space-y-3 flex-shrink-0">
          {/* Intervention Weights */}
          <div className="bg-black/40 rounded-xl border border-cyan-500/30 p-3">
            <h3 className="text-xs text-cyan-400 mb-3 uppercase tracking-wide">Intervention Weights</h3>
            <Slider label="Retrieval Heat" value={activityConfig.retrievalWeight} onChange={(v) => setActivityConfig(p => ({ ...p, retrievalWeight: v }))} min={0} max={0.5} color="#22d3ee" />
            <Slider label="Reinforcement" value={activityConfig.reinforcementWeight} onChange={(v) => setActivityConfig(p => ({ ...p, reinforcementWeight: v }))} min={0} max={0.5} color="#a78bfa" />
            <Slider label="Network Density" value={activityConfig.networkWeight} onChange={(v) => setActivityConfig(p => ({ ...p, networkWeight: v }))} min={0} max={0.5} color="#34d399" />
            <Slider label="Context Anchor" value={activityConfig.anchorWeight} onChange={(v) => setActivityConfig(p => ({ ...p, anchorWeight: v }))} min={0} max={0.5} color="#fbbf24" />
          </div>

          {/* Lock Speed */}
          <div className="bg-black/40 rounded-xl border border-white/10 p-3">
            <h3 className="text-xs text-white/60 mb-3 uppercase tracking-wide">Sigmoid Shape</h3>
            <Slider label="Lock Speed (k)" value={activityConfig.lockSpeed} onChange={(v) => setActivityConfig(p => ({ ...p, lockSpeed: v }))} min={0.1} max={1.0} step={0.05} />
            <Slider label="Connection Threshold" value={config.crossSessionThreshold} onChange={(v) => setConfig(p => ({ ...p, crossSessionThreshold: v }))} min={0.1} max={0.5} />
          </div>

          {/* Warnings */}
          <div>
            <h3 className="text-xs text-white/60 mb-2 uppercase tracking-wide">System Status</h3>
            <WarningPanel warnings={warnings} />
          </div>

          {/* Legend */}
          <div className="bg-black/40 rounded-xl border border-white/10 p-3">
            <h3 className="text-xs text-white/60 mb-2 uppercase tracking-wide">Lock-In States</h3>
            <div className="space-y-1.5">
              {[
                { state: 'locked', label: 'Locked (L ≥ 0.70)', desc: 'Permanent memory' },
                { state: 'active', label: 'Active (0.30-0.70)', desc: 'Healthy, can shift' },
                { state: 'drifting', label: 'Drifting (L ≤ 0.30)', desc: 'At risk of loss' },
              ].map(({ state, label, desc }) => (
                <div key={state} className="flex items-center gap-2">
                  <div className="w-3 h-3 rounded-full" style={{ backgroundColor: STATE_COLORS[state] }} />
                  <div>
                    <div className="text-xs" style={{ color: STATE_COLORS[state] }}>{label}</div>
                    <div className="text-xs text-white/40">{desc}</div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Center: Timeline */}
        <div className="flex-1 overflow-hidden">
          <div className="bg-black/30 rounded-xl border border-white/10 p-4 relative" onClick={clearSelection}>
            <div className="flex items-center justify-between mb-4 text-xs text-white/40">
              <span>← Past</span>
              <span>Memory Timeline</span>
              <span>Present →</span>
            </div>

            <div ref={containerRef} className="relative overflow-x-auto pb-4" style={{ minHeight: 380 }}>
              <ThreadCanvas
                threads={threads}
                nodePositions={nodePositions}
                containerRef={containerRef}
                selectedThread={selectedThread}
                highlightedThreads={highlightedThreads}
              />

              <div className="flex gap-3 relative" style={{ zIndex: 20 }}>
                {sessions.map((session) => (
                  <SessionStack
                    key={session.id}
                    session={session}
                    selectedNode={selectedNode}
                    onNodeSelect={handleNodeSelect}
                    highlightedNodes={highlightedNodes}
                    onNodePosition={handleNodePosition}
                  />
                ))}
              </div>
            </div>
          </div>
        </div>

        {/* Right Panel */}
        <div className="w-64 space-y-3 flex-shrink-0">
          {/* Thread List by State */}
          <div className="bg-black/40 rounded-xl border border-white/10 p-3">
            <h3 className="text-xs text-white/60 mb-2 uppercase tracking-wide">Threads by State</h3>
            <div className="space-y-1 max-h-40 overflow-y-auto">
              {threads
                .sort((a, b) => b.lockIn - a.lockIn)
                .slice(0, 8)
                .map(thread => (
                  <div
                    key={thread.id}
                    onClick={(e) => {
                      e.stopPropagation();
                      setSelectedThread(thread);
                      setHighlightedThreads(new Set([thread.id]));
                      setHighlightedNodes(new Set([thread.from.nodeId, thread.to.nodeId]));
                    }}
                    className="p-1.5 rounded cursor-pointer hover:bg-white/5 flex items-center gap-2"
                    style={{ borderLeft: `3px solid ${STATE_COLORS[thread.state]}` }}
                  >
                    <span className="text-xs font-mono" style={{ color: STATE_COLORS[thread.state] }}>
                      {(thread.lockIn * 100).toFixed(0)}%
                    </span>
                    <span className="text-xs text-white/50 truncate flex-1">
                      {thread.resonance.sharedTags?.slice(0, 2).join(', ')}
                    </span>
                  </div>
                ))}
            </div>
          </div>

          {/* Selected Thread Detail */}
          {selectedThread && (
            <ThreadDetail
              thread={selectedThread}
              activityConfig={activityConfig}
              onClose={() => {
                setSelectedThread(null);
                setHighlightedThreads(new Set());
                setHighlightedNodes(new Set());
              }}
            />
          )}

          {/* Instructions */}
          {!selectedThread && (
            <div className="bg-black/40 rounded-xl border border-white/10 p-3">
              <h3 className="text-xs text-white/60 mb-2 uppercase tracking-wide">How It Works</h3>
              <ul className="text-xs text-white/50 space-y-1">
                <li>• <span className="text-green-400">Green</span> = Locked (permanent)</li>
                <li>• <span className="text-cyan-400">Cyan</span> = Active (healthy)</li>
                <li>• <span className="text-orange-400">Orange</span> = Drifting (at risk)</li>
                <li>• Thread thickness = lock-in strength</li>
                <li>• Dashed = drifting threads</li>
                <li>• Click thread to see sigmoid curve</li>
              </ul>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
